			<div class="elementor-widget-wrap elementor-element-populated">
								<div class="elementor-element elementor-element-86d476a elementor-absolute elementor-widget elementor-widget-html" data-id="86d476a" data-element_type="widget" data-settings="{&quot;_position&quot;:&quot;absolute&quot;}" data-widget_type="html.default">
				<div class="elementor-widget-container">
			<script>
    const slider = document.querySelector(".js--ludi-hotspot").parentElement;
let isDown = false;
let startX;
let scrollLeft;
slider.style.position = 'relative';

slider.addEventListener("mousedown", (e) => {
  isDown = true;
  slider.classList.add("active");
  startX = e.pageX - slider.offsetLeft;
  scrollLeft = slider.scrollLeft;
});
slider.addEventListener("mouseleave", () => {
  isDown = false;
  slider.classList.remove("active");
});
slider.addEventListener("mouseup", () => {
  isDown = false;
  slider.classList.remove("active");
});
slider.addEventListener("mousemove", (e) => {
  if (!isDown) return;
  e.preventDefault();
  const x = e.pageX - slider.offsetLeft;
  const walk = (x - startX) * 1.3; //scroll-fast
  slider.scrollLeft = scrollLeft - walk;
  //console.log(walk);
});
</script>		</div>
